import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Link as ScrollLink } from 'react-scroll';
import './header.css';
import bullesDevImage from './requindev.png';

const Header = () => {
  const location = useLocation();

  const scrollToProjects = () => {
    if (location.pathname !== '/') {
      // If not on the home page, navigate to the home page first
      window.location.href = '/#projets-section';
    } else {
      // If already on the home page, scroll to the section
      ScrollLink.scrollTo('projets-section', {
        smooth: true,
        duration: 500,
      });
    }
  };

  return (
    <header>
      <div className="bullesdev">
        <img src={bullesDevImage} alt="Les bulles du dev" />
      </div>
      <nav>
        <div className="liensnav">
          <Link to="/" relative="path">
            <p>Accueil</p>
          </Link>
          <Link to="/pageQjs" relative="path">
            <p>Mon évolution</p>
          </Link>
          <Link to="/competences" relative="path">
            <p>Mes compétences</p>
          </Link>
          <p onClick={scrollToProjects}>Mes projets réalisés</p>
          <ScrollLink to="footer" smooth={true} duration={500}>
            <p>Contact</p>
          </ScrollLink>
        </div>
      </nav>
    </header>
  );
};

export default Header;
